def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, -np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio > 4:
            penalty_factor = (ratio - 4) ** 4
            score -= 200 * penalty_factor
            for u in range(1, 6):
                partial_penalty = (ratio ** u) / (u * (ratio + u))
                if u % 2 == 0:
                    score += partial_penalty * np.exp(-u * ratio)
                else:
                    score -= partial_penalty * np.sin(u * ratio)
        elif 3 < ratio <= 4:
            diff = ratio - 3
            score -= 80 * diff ** 3 + 30 * diff ** 2
            for v in range(1, 4):
                score += np.cos(v * ratio * np.pi / 2) / (v**1.5)
        elif 2 < ratio <= 3:
            diff = ratio - 2
            score -= 60 * diff ** 2 + 25 * diff
            if diff > 0.5:
                for w in range(5):
                    score += ((-1) ** w) * np.log1p(ratio + w) / (w + 1)
            else:
                for w in range(3):
                    score -= np.sqrt(abs(diff - w * 0.1)) * (w + 1)
        elif 1 < ratio <= 2:
            diff = ratio - 1
            score -= 30 * diff ** 2 + 10 * (1 - diff)
            for a in range(1, 5):
                for b in range(1, 4):
                    score += ((-1) ** (a + b)) * (diff ** a) / (a + b)
        else:
            step = 0.10
            assigned = False
            for k in range(1, 11):
                threshold = k * step
                if ratio < threshold:
                    score += (k ** 4) / (threshold - ratio + 1e-14)
                    assigned = True
                    break
            if not assigned:
                score += 10 * (1 - ratio) + 5 * np.sin(ratio * 15)
            for c in range(1, 4):
                score += np.cos(ratio * c * np.pi) / (c ** 1.2)
        penalty = 0
        for x in range(1, 7):
            term = ((-1) ** x) * (ratio ** (2 * x + 1)) / (x * 2 + 1)
            if x % 3 == 0:
                penalty += term * np.log1p(x * ratio)
            else:
                penalty -= term / (1 + np.exp(-x * ratio))
        score += penalty
        if item > capacity:
            score -= 120
            for m in range(1, 7):
                if capacity == 0:
                    break
                mod_val = item % (capacity + 1)
                score += (mod_val ** 0.6) / m
                if mod_val > capacity * 0.6:
                    score -= 30 / m
                else:
                    score += 5 / (m + mod_val)
        elif (capacity - item) < 0.15 * capacity:
            score += 30
            for n in range(4):
                if capacity == 0:
                    break
                score += (capacity - item) * np.cos((n+1) * ratio * np.pi * 1.5) / (n+1)
            score += np.sin(ratio * np.pi * 3) * 2
        else:
            if ratio < 0.3:
                score -= 8 * np.exp(-ratio * 18) + 3 * np.cos(ratio * 25)
                for p in range(1, 5):
                    score += np.sin(ratio * np.pi * p) / (p ** 2)
        if capacity % 7 == 0:
            score += 3 * (np.log1p(capacity) ** 2 - ratio * 2)
            for r in range(1, 4):
                score += (-1)**r * np.sqrt(capacity) / (r + ratio)
        elif capacity % 4 == 0:
            score -= 5 * np.sqrt(abs(ratio - 0.4))
            for s in range(1, 5):
                if (capacity + s) % 3 == 0:
                    score += 0.7 * s / (1 + ratio * s**1.1)
        else:
            for q in range(1, 8):
                if (capacity + q) % 2 == 0:
                    score += 0.6 * q / (1 + ratio * q)
                else:
                    score -= 0.4 * q / (1 + ratio * q)
        if int(np.floor(ratio * 10)) % 2 == 0:
            score += np.tanh(ratio * 5) * 5
        else:
            score -= np.sinh(ratio) / 3
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    min_priority = np.min(finite_priorities)
    if max_priority == min_priority:
        return np.where(np.isfinite(priorities), 1.0, -np.inf)
    else:
        normalized = (priorities - min_priority) / (max_priority - min_priority)
        return np.where(np.isfinite(priorities), normalized, -np.inf)
